                            CREATE View [SSRS].[League_SeasonCurrLast_STD]    as  Select    League_ID,    Name,    Year_of_Fixture,    Sum([No Result])[No Result],     Sum(Abandoned  )Abandoned  ,   Sum(Cancelled  )Cancelled  ,   Sum(Conceded   )Conceded   ,   Sum(InProgress )InProgress ,   Sum(Win     )Win     ,   Sum(ShortSided )ShortSided     FROM   (  SELECT Case [League_ID] When 15363 then 8205 Else League_ID END League_ID        ,Case [League_ID] When 8205 then 'Northumberland and Tyneside Cricket League' Else REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' ') END AS Name         ,[year_of_Fixture]        ,[MonthofFixture]        ,[No Result]        ,[Abandoned]        ,[Cancelled]        ,[Conceded]        ,[InProgress]        ,[Win]        ,[ShortSided]    FROM [SSRS].[Leagues_SeasonTD_2026] a    UNION      Select Case [League_ID] When 15363 then 8205 Else League_ID END League_ID        ,Case [League_ID] When 8205 then 'Northumberland and Tyneside Cricket League' Else REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' ') END AS Name         ,[year_of_Fixture]        ,[MonthofFixture]        ,[No Result]        ,[Abandoned]        ,[Cancelled]        ,[Conceded]        ,[InProgress]        ,[Win]        ,[ShortSided]  FROM    [SSRS].[Leagues_2025Season]     )A     where MonthofFixture <=  DATEPART(month,getdate())-1   group by League_ID,    Name,    Year_of_Fixture                